UPDATE DISPOSALS
SET reason_Id = #{reasonId}
WHERE disposal_Id = #{disposalId}

mapper.select:
SELECT IFNULL(ROUND(
SUM(d.disposalCountAll) * 100 /
NULLIF(SUM(f.foodMaterialCountAll), 0), 2
), 0) AS disposalRate
FROM DISPOSALS d
JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id
WHERE f.bId = #{bId}
AND d.disposalDate >= #{startDate}
AND d.disposalDate < #{endDate}

SELECT IFNULL(SUM(d.disposalPrice), 0) AS totalDisposalPrice
FROM DISPOSALS d
JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id
WHERE f.bId = #{bId}
AND d.disposalDate BETWEEN #{startDate} AND #{endDate}
